import sys

def main():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        D=int(next(it)); d=int(next(it)); A=int(next(it)); B=int(next(it)); C=int(next(it))
        total=D*d
        if total>=42:
            out.append(str(C))
        elif total>=21:
            out.append(str(B))
        elif total>=10:
            out.append(str(A))
        else:
            out.append('0')
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    main()

